class Solution:
    def minTime(self, n, edges, k):
        def components(t):
            parent = list(range(n))
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            cnt = n
            for u, v, tm in edges:
                if tm > t:
                    ru, rv = find(u), find(v)
                    if ru != rv:
                        parent[ru] = rv
                        cnt -= 1
            return cnt
        cands = sorted(set([0] + [e[2] for e in edges]))
        for t in cands:
            if components(t) >= k:
                return t
        return cands[-1] if cands else 0

