            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            cnt = n
            for u, v, tm in edges:
                if tm > t:
                    ru, rv = find(u), find(v)
                    if ru != rv:
                        parent[ru] = rv
                        cnt -= 1
            return cnt
        cands = sorted(set([0] + [e[2] for e in edges]))
        lo, hi = 0, len(cands) - 1
        ans = cands[-1]
        while lo <= hi:
            mid = (lo + hi) // 2
            if components(cands[mid]) >= k:
                ans = cands[mid]
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

