var minTime = function(n, edges, k) {
    const components = (t) => {
        const parent = Array.from({length: n}, (_, i) => i);
        const find = (x) => {
            while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
            return x;
        };
        let cnt = n;
        for (const [u, v, tm] of edges) {
            if (tm > t) {
                const ru = find(u), rv = find(v);
                if (ru !== rv) { parent[ru] = rv; cnt--; }
            }
        }
        return cnt;
    };
    const set = new Set([0]);
    for (const e of edges) set.add(e[2]);
    const cands = Array.from(set).sort((a, b) => a - b);
    let lo = 0, hi = cands.length - 1, ans = cands[cands.length - 1];
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (components(cands[mid]) >= k) { ans = cands[mid]; hi = mid - 1; }
        else lo = mid + 1;
    }
    return ans;
};
